  ('locality-6f0ba476-moex-00565', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', 'A公司109年度所得稅結算申報營業收入2,000萬元、營業成本1,600萬元、營業費用200萬 元、營業外收入50萬元，適用之所得額標準為120萬元，按同業利潤標準毛利率及淨利率核 算之所得額分別為180萬元及160萬元，A公司於調查時未提示有關成本之帳簿憑證，則A 公司109年度所得稅結算申報核定營業淨利應為：', '["160萬元", "180萬元", "200萬元", "250萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00566', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '我國個人自110年7月1日起，交易105年1月1日以後取得的房地，依持有期間按差別稅 率45%、35%、20%、15%計算房地交易所得稅額，請問前開差別稅率適用之持有期間為何？', '["1年以內、超過1年未逾2年、超過2年未逾10年、超過10年", "1年以內、超過1年未逾5年、超過5年未逾10年、超過10年", "2年以內、超過2年未逾5年、超過5年未逾10年、超過10年", "2年以內、超過2年未逾10年、超過10年未逾15年、超過15年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00567', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '下列何者所得，非屬於我國所得稅法之免納所得？', '["各級政府公有事業之所得", "依法經營不對外營業消費合作社之盈餘", "個人存放在銀行定存單而取得之利息", "人身保險、勞工保險及軍、公教保險之保險給付"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00568', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '甲君110年度有下列所得及支出（均為新臺幣），應計入個人基本所得額的項目為何？①香港', '["捐贈土地予政府 200 萬元", "依所得稅法規定計算之綜合所得淨 額1,000萬元", "交易設立1年、未上市櫃，且經核定為高風險新創事業公司之股票交易所 得300萬元  ⑤綜合所得稅結算申報時，選擇分開計稅之股利200萬元", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00569', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '甲為受僱演員，110年度接演古裝劇的薪資收入300萬元，非表演的薪資收入100萬元，當 年度自行訂製表演專用服裝支付費用15萬元、購置演出使用之道具支付費用5萬元、參加政 府訓練機構開設進修課程支付費用5萬元。請問甲110年度應申報薪資所得金額為何？', '["400萬元", "380萬元", "375萬元", "373萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00570', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '所得稅法規定，營利事業當年度之盈餘未作分配者，應就該未分配盈餘加徵營利事業所得稅， 下列敘述何者錯誤？', '["加徵5%所得稅", "可減除依股東會決議，應由稅後純益轉為資本公積者", "可減除依其他法律規定，由主管機關命令自當年度盈餘已提列特別盈餘公積或限制分配 部分", "可減除依本國與外國所訂之契約，應提列之償債基金準備"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00571', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '甲商號為適用查定課徵營業稅之小規模營業人，110年1至3月份的銷售額經主管稽徵機關 查定為每月新臺幣180,000元，另經其申報符合規定之可扣抵進項稅額110年1至3月合計 為15,000元，則該商號當期的營業稅應納稅額為多少？', '["3,900元", "4,200元", "6,800元", "7,500元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00572', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '有關營業稅之申報繳納，下列何者正確？①一般加值型營業人應以每2個月為一期，於次期', '["營業人銷售適用加值型及非加值型營業稅法規定之免稅貨物者，得申 請以每月為一期申報繳納", "按查定計算營業稅額之小規模營業人，由主管稽徵機關查定其 銷售額及稅額，每3個月填發繳款書通知繳納一次", "按查定計算營業稅額之特種飲食業營 業人，由主管稽徵機關查定其銷售額及稅額，每2個月填發繳款書通知繳納一次  ⑤應辦理 申報繳納營業稅之營業人，當期無銷售額者，仍應辦理營業稅申報", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00573', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '下列何者非適用營業稅零稅率之貨物或勞務？', '["免稅商店銷售與過境或出境旅客之貨物", "甲公司介紹國內乙公司向國外A廠商進口原料，取得之外匯佣金收入", "丙公司接受國外 B 客戶訂購貨物後，轉向第三國 C 供應商訂貨並由 C 供應商直接交貨給 B客戶，按佣金收入列帳之信用狀差額", "公司銷售與個人經營之遠洋漁船所使用之貨物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00574', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '下列有關營業稅課稅範圍之敘述，何者正確？', '["營業人進口貨物，除符合加值型及非加值型營業稅法第9條免徵營業稅規定外，應於進口 時由海關代徵營業稅", "個人與在中華民國境內無固定營業場所之外國公司簽約購買大廈設計藍圖，非屬營業稅課 稅範圍", "自國外進入我國政府核定之自由貿易港區及保稅工廠、保稅倉庫、物流中心等區，應於進 入該等專區時由海關代徵營業稅", "醫院出租財產取得租金收入，免課徵營業稅，應由承租人依所得稅法第88條規定按給付之 租金扣繳所得稅款"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:06+00:00", "source_pdf_sha1": "4b41bbed0214", "answer_pdf_sha1": "6fc5642b3ef9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
